// Auto-generated: uploads Excel files to Google Drive as Google Sheets
// This preserves ALL formatting, formulas, colors, and structure

function uploadAllSpreadsheets() {
  var folder = DriveApp.createFolder('Epictete - Catégories Excel');
  var files = {"Boissons.xlsx":"","Économat Pdt Italien.xlsx":"","Fournisseurs.xlsx":"","Fromage.xlsx":"","Inventaire_Complet.xlsx":"","Légumes.xlsx":"","Poisson.xlsx":"","Suivi_Financier_Restaurant 04.04.2026.xlsx":"","Suivi_Inventaire.xlsx":"","Viande.xlsx":"","Économat.xlsx":""};
  
  for (var name in files) {
    Logger.log('Uploading: ' + name);
    var decoded = Utilities.base64Decode(files[name]);
    var blob = Utilities.newBlob(decoded, 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', name);
    
    // Create file in Drive - it stays as xlsx
    var file = folder.createFile(blob);
    
    // Convert to Google Sheets format
    var config = {
      title: name.replace('.xlsx', ''),
      mimeType: MimeType.GOOGLE_SHEETS,
      parents: [{id: folder.getId()}]
    };
    
    var gsheet = Drive.Files.copy({title: name.replace('.xlsx', ''), mimeType: MimeType.GOOGLE_SHEETS}, file.getId());
    var gsFile = DriveApp.getFileById(gsheet.id);
    folder.addFile(gsFile);
    
    // Remove the original xlsx
    folder.removeFile(file);
    file.setTrashed(true);
    
    // Share with service account
    gsFile.addEditor('epictete@epictete-492501.iam.gserviceaccount.com');
    
    Logger.log('Done: ' + name + ' -> ' + gsFile.getUrl());
  }
  
  Logger.log('\nAll done! Folder: ' + folder.getUrl());
}
